import math

PI = 3.1415926535

def realcompare(a: float, b: float) -> str:
    if math.isclose(a, b, rel_tol=1e-6, abs_tol=1e-6):
        return "EQ"
    elif a < b:
        return "LT"
    else:
        return "GT"

def decide(numpoints: int, x: list, y: list, parameters: dict, lcm: list, pum_diag: list):
    cmv = [False] * 15

    def dist(i, j):
        return math.hypot(x[i] - x[j], y[i] - y[j])

    def triangle_area(i, j, k):
        return 0.5 * abs(x[i]*(y[j] - y[k]) + x[j]*(y[k] - y[i]) + x[k]*(y[i] - y[j]))

    def angle(i, j, k):
        if (realcompare(x[i], x[j]) == "EQ" and realcompare(y[i], y[j]) == "EQ") or \
           (realcompare(x[k], x[j]) == "EQ" and realcompare(y[k], y[j]) == "EQ"):
            return None
        v1x, v1y = x[i] - x[j], y[i] - y[j]
        v2x, v2y = x[k] - x[j], y[k] - y[j]
        dot = v1x * v2x + v1y * v2y
        mag1 = math.hypot(v1x, v1y)
        mag2 = math.hypot(v2x, v2y)
        if mag1 == 0.0 or mag2 == 0.0:
            return None
        val = dot / (mag1 * mag2)
        val = max(-1.0, min(1.0, val))
        return math.acos(val)

    def mec_radius(i, j, k):
        d12 = dist(i, j)
        d23 = dist(j, k)
        d31 = dist(k, i)
        sides = sorted([d12, d23, d31])
        a, b, c = sides[0], sides[1], sides[2]

        if realcompare(c**2, a**2 + b**2) in ("GT", "EQ"):
            return c / 2.0
        else:
            area = triangle_area(i, j, k)
            if realcompare(area, 0.0) == "EQ":
                return c / 2.0
            return (a * b * c) / (4.0 * area)

    def get_quad(px, py):
        x_ge_0 = realcompare(px, 0.0) in ("GT", "EQ")
        y_ge_0 = realcompare(py, 0.0) in ("GT", "EQ")
        x_gt_0 = realcompare(px, 0.0) == "GT"
        y_lt_0 = realcompare(py, 0.0) == "LT"
        x_lt_0 = realcompare(px, 0.0) == "LT"
        x_le_0 = realcompare(px, 0.0) in ("LT", "EQ")

        if x_ge_0 and y_ge_0: return 1
        if x_lt_0 and y_ge_0: return 2
        if x_le_0 and y_lt_0: return 3
        if x_gt_0 and y_lt_0: return 4
        return 1

    # LIC 1
    for i in range(numpoints - 1):
        if realcompare(dist(i, i + 1), parameters["LENGTH1"]) == "GT":
            cmv[0] = True
            break

    # LIC 2
    for i in range(numpoints - 2):
        if realcompare(mec_radius(i, i + 1, i + 2), parameters["RADIUS1"]) == "GT":
            cmv[1] = True
            break

    # LIC 3
    for i in range(numpoints - 2):
        ang = angle(i, i + 1, i + 2)
        if ang is not None:
            if realcompare(ang, PI - parameters["EPSILON"]) == "LT" or \
               realcompare(ang, PI + parameters["EPSILON"]) == "GT":
                cmv[2] = True
                break

    # LIC 4
    for i in range(numpoints - 2):
        if realcompare(triangle_area(i, i + 1, i + 2), parameters["AREA1"]) == "GT":
            cmv[3] = True
            break

    # LIC 5
    q_pts = parameters["Q_PTS"]
    for i in range(numpoints - q_pts + 1):
        quads = set()
        for j in range(q_pts):
            quads.add(get_quad(x[i + j], y[i + j]))
        if len(quads) > parameters["QUADS"]:
            cmv[4] = True
            break

    # LIC 6
    for i in range(numpoints - 1):
        if realcompare(x[i + 1], x[i]) == "LT":
            cmv[5] = True
            break

    # LIC 7
    if numpoints >= 3:
        n_pts = parameters["N_PTS"]
        for i in range(numpoints - n_pts + 1):
            first = i
            last = i + n_pts - 1
            for j in range(first, last + 1):
                if realcompare(x[first], x[last]) == "EQ" and realcompare(y[first], y[last]) == "EQ":
                    d = dist(j, first)
                else:
                    num = abs((y[last] - y[first]) * x[j] - (x[last] - x[first]) * y[j] + x[last] * y[first] - y[last] * x[first])
                    den = dist(first, last)
                    d = num / den
                if realcompare(d, parameters["DIST"]) == "GT":
                    cmv[6] = True
                    break
            if cmv[6]:
                break

    # LIC 8
    if numpoints >= 3:
        k_pts = parameters["K_PTS"]
        for i in range(numpoints - k_pts - 1):
            if realcompare(dist(i, i + k_pts + 1), parameters["LENGTH1"]) == "GT":
                cmv[7] = True
                break

    # LIC 9
    if numpoints >= 5:
        a_pts = parameters["A_PTS"]
        b_pts = parameters["B_PTS"]
        for i in range(numpoints - a_pts - b_pts - 2):
            p1 = i
            p2 = i + a_pts + 1
            p3 = p2 + b_pts + 1
            if realcompare(mec_radius(p1, p2, p3), parameters["RADIUS1"]) == "GT":
                cmv[8] = True
                break

    # LIC 10
    if numpoints >= 5:
        c_pts = parameters["C_PTS"]
        d_pts = parameters["D_PTS"]
        for i in range(numpoints - c_pts - d_pts - 2):
            p1 = i
            p2 = i + c_pts + 1
            p3 = p2 + d_pts + 1
            ang = angle(p1, p2, p3)
            if ang is not None:
                if realcompare(ang, PI - parameters["EPSILON"]) == "LT" or \
                   realcompare(ang, PI + parameters["EPSILON"]) == "GT":
                    cmv[9] = True
                    break

    # LIC 11
    if numpoints >= 5:
        e_pts = parameters["E_PTS"]
        f_pts = parameters["F_PTS"]
        for i in range(numpoints - e_pts - f_pts - 2):
            p1 = i
            p2 = i + e_pts + 1
            p3 = p2 + f_pts + 1
            if realcompare(triangle_area(p1, p2, p3), parameters["AREA1"]) == "GT":
                cmv[10] = True
                break

    # LIC 12
    if numpoints >= 3:
        g_pts = parameters["G_PTS"]
        for i in range(numpoints - g_pts - 1):
            if realcompare(x[i + g_pts + 1], x[i]) == "LT":
                cmv[11] = True
                break

    # LIC 13
    if numpoints >= 3:
        k_pts = parameters["K_PTS"]
        cond1 = False
        cond2 = False
        for i in range(numpoints - k_pts - 1):
            if realcompare(dist(i, i + k_pts + 1), parameters["LENGTH1"]) == "GT":
                cond1 = True
                break
        for i in range(numpoints - k_pts - 1):
            if realcompare(dist(i, i + k_pts + 1), parameters["LENGTH2"]) == "LT":
                cond2 = True
                break
        if cond1 and cond2:
            cmv[12] = True

    # LIC 14
    if numpoints >= 5:
        a_pts = parameters["A_PTS"]
        b_pts = parameters["B_PTS"]
        cond1 = False
        cond2 = False
        for i in range(numpoints - a_pts - b_pts - 2):
            p1 = i
            p2 = i + a_pts + 1
            p3 = p2 + b_pts + 1
            if realcompare(mec_radius(p1, p2, p3), parameters["RADIUS1"]) == "GT":
                cond1 = True
                break
        for i in range(numpoints - a_pts - b_pts - 2):
            p1 = i
            p2 = i + a_pts + 1
            p3 = p2 + b_pts + 1
            if realcompare(mec_radius(p1, p2, p3), parameters["RADIUS2"]) in ("LT", "EQ"):
                cond2 = True
                break
        if cond1 and cond2:
            cmv[13] = True

    # LIC 15
    if numpoints >= 5:
        e_pts = parameters["E_PTS"]
        f_pts = parameters["F_PTS"]
        cond1 = False
        cond2 = False
        for i in range(numpoints - e_pts - f_pts - 2):
            p1 = i
            p2 = i + e_pts + 1
            p3 = p2 + f_pts + 1
            if realcompare(triangle_area(p1, p2, p3), parameters["AREA1"]) == "GT":
                cond1 = True
                break
        for i in range(numpoints - e_pts - f_pts - 2):
            p1 = i
            p2 = i + e_pts + 1
            p3 = p2 + f_pts + 1
            if realcompare(triangle_area(p1, p2, p3), parameters["AREA2"]) == "LT":
                cond2 = True
                break
        if cond1 and cond2:
            cmv[14] = True

    # Build PUM
    pum = [[False] * 15 for _ in range(15)]
    for i in range(15):
        for j in range(15):
            if i == j:
                pum[i][j] = pum_diag[i]
            else:
                op = lcm[i][j]
                if op == "ANDD":
                    pum[i][j] = cmv[i] and cmv[j]
                elif op == "ORR":
                    pum[i][j] = cmv[i] or cmv[j]
                elif op == "NOTUSED":
                    pum[i][j] = True

    # Build FUV
    fuv = [False] * 15
    for i in range(15):
        if not pum[i][i]:
            fuv[i] = True
        else:
            all_true = True
            for j in range(15):
                if not pum[i][j]:
                    all_true = False
                    break
            fuv[i] = all_true

    # Launch decision
    launch = all(fuv)

    return (cmv, pum, fuv, launch)
